FOR t IN
  (SELECT * FROM `undefined.dashboards.days_with_missing_stats`())
DO
  DELETE FROM `undefined.dashboards.dashboards-data` WHERE as_of_record_time = t.as_of_record_time;

  INSERT INTO `undefined.dashboards.dashboards-data`
    SELECT * FROM `undefined.functions.all_dashboard_stats`(t.as_of_record_time, `undefined.functions.migration_id_at_time`(t.as_of_record_time));

END FOR;
